/* ringbuf.h — 环形缓冲区 ADT 接口定义 */
#ifndef RINGBUF_H
#define RINGBUF_H

#include <stdint.h>
#include <stddef.h>

#define RINGBUF_SIZE 256u
#define RINGBUF_MASK (RINGBUF_SIZE - 1u)

typedef struct {
    uint8_t buffer[RINGBUF_SIZE];
    volatile uint16_t head;
    volatile uint16_t tail;
} ringbuf_t;

void ringbuf_init(ringbuf_t *rb);
size_t ringbuf_count(const ringbuf_t *rb);
int ringbuf_push(ringbuf_t *rb, uint8_t byte);
int ringbuf_read_block(
    const ringbuf_t *rb,
    uint8_t *out,
    size_t max_len
);

#endif /* RINGBUF_H */

static volatile uint16_t transferred = 0;
static uint16_t prev_head = 0;

void HAL_UART_RxCpltCallback(UART_HandleTypeDef *huart)
{
    if (huart->Instance == USART2) {
        /* 步骤1: 内存屏障，确保 DMA 写入对 CPU 可见 */
        __DSB();

        /* 步骤2: 步进更新 head，不读 CNDTR */
        transferred = (transferred + 1) & RING_MASK;

        /* 步骤3: 溢出检测 —— 差值超一半说明写太满 */
        uint16_t diff = transferred - prev_head;
        if ((diff & RING_MASK) > (RINGBUF_SIZE >> 1)) {
            overflow_flag = true;
        }
        prev_head = transferred;

        /* 步骤4: 用局部变量做 head 快照，避免 ISR 干扰 */
        uint16_t head_snapshot = rx_ringbuf.head;

        /* 步骤5: 通知消费者有新数据 */
        ringbuf_notify_written(&rx_ringbuf, head_snapshot);
    }
}

/* ❌ 重构前：裸指针算术，全局变量泄漏 */
volatile uint16_t rx_head = 0;
volatile uint16_t rx_tail = 0;
uint8_t rx_buf[256];

void DMA_TC_Callback(void) {
    __DSB();
    rx_head = (rx_head + 1) & 255;  /* 魔法数字 */
}

void parse_protocol(void) {
    uint16_t avail = rx_head >= rx_tail
                     ? rx_head - rx_tail
                     : 256 - rx_tail + rx_head;
    for (uint16_t i = 0; i < avail; i++) {
        uint8_t b = rx_buf[rx_tail];  /* 直接访问全局 */
        rx_tail = (rx_tail + 1) & 255;
        process_byte(b);               /* 协议解析 */
    }
}

/* ✅ 重构后：ADT 封装，接口清晰 */
void ringbuf_push(ringbuf_t *rb, uint8_t byte) {
    size_t pos = rb->head & RINGBUF_MASK;
    rb->buffer[pos] = byte;
    __DSB();
    rb->head = (rb->head + 1) & RINGBUF_MASK;
}

size_t ringbuf_read_block(
    const ringbuf_t *rb,
    uint8_t *out, size_t max
) {
    size_t avail = ringbuf_count(rb);
    size_t n = (avail < max) ? avail : max;
    for (size_t i = 0; i < n; i++) {
        size_t pos = rb->tail & RINGBUF_MASK;
        out[i] = rb->buffer[pos];
        rb->tail = (rb->tail + 1) & RINGBUF_MASK;
    }
    return n;
}

void parse_protocol(void) {
    uint8_t frame[64];
    size_t n = ringbuf_read_block(&rx_ringbuf, frame, sizeof(frame));
    for (size_t i = 0; i < n; i++) {
        process_byte(frame[i]);
    }
}
